const hubspot = require('@hubspot/api-client');
const http = require("https");

const objectType = "p21710069_Utility";
const associationTypeId = 92;

const Ahjs = async () =>
{
    let ahjs = [];
    let after = undefined;

    const hc = new hubspot.Client
    ({
        accessToken: process.env.photon_association_handler
    });

    while (1)
    {
        let ahjResponse = await hc.crm.objects.basicApi.getPage
        (
            objectType, 
            100, 
            after, 
            ["record_name"], 
            undefined, 
            undefined, 
            false
          );

        ahjResponse = ahjResponse.body;

        if (ahjResponse.results)
        {
      	    ahjs = ahjs.concat(ahjResponse.results);
        }

        if (ahjResponse && ahjResponse.hasOwnProperty("paging") && ahjResponse.paging && ahjResponse.paging.hasOwnProperty("next") && ahjResponse.paging.next && ahjResponse.paging.next.hasOwnProperty("after") && ahjResponse.paging.next.after)
        {
          	after = ahjResponse.paging.next.after;
          	continue;
        }

        break;
    }  

    return ahjs;
};

const CreateDealAhjAssoc = async (dealId, ahjId) =>
{
    let GeneratorFunc = (resolve, reject) =>
    {      
        let opts = 
        {
            "method": "PUT",
            "hostname": "api.hubapi.com",
            "port": null,
            "path": "/crm/v4/objects/DEAL/" + dealId + "/associations/" + objectType + "/" + ahjId,
            "headers":
            {
                "accept": "application/json",
                "content-type": "application/json",
                "authorization": "Bearer " + process.env.photon_association_handler
            }
        };

        let req = http.request(opts, (res) =>
        {
            let chunks = [];

            res.on("data", (chunk) =>
            {
                chunks.push(chunk);
            });

            res.on("end", () =>
            {
                resolve();
            });
        });

        req.write(JSON.stringify([{"associationCategory": "USER_DEFINED", "associationTypeId": associationTypeId}]));
        req.end();
    };

    return new Promise(GeneratorFunc);
};

exports.main = async (event, callback) => {

  /*****
